using sv_0055fbb2415f4378b3190c11cb8d527c.Client.Services;

namespace sv_0055fbb2415f4378b3190c11cb8d527c.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new ShipmentDetails(
            "TRK-001",
            "In Transit",
            "Chicago, IL",
            new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero), "Package picked up"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), "Arrived at sorting facility"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 23, 9, 15, 0, TimeSpan.Zero), "Departed Chicago hub"),
            ]),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "Austin, TX",
            new DateTimeOffset(2026, 5, 22, 12, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero), "Package picked up"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 19, 16, 45, 0, TimeSpan.Zero), "In transit to destination"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 21, 11, 0, 0, TimeSpan.Zero), "Out for delivery"),
                new StatusUpdate(new DateTimeOffset(2026, 5, 21, 14, 20, 0, TimeSpan.Zero), "Delivered"),
            ]),
        ["TRK-003"] = new ShipmentDetails(
            "TRK-003",
            "Processing",
            "Seattle, WA",
            new DateTimeOffset(2026, 6, 1, 18, 0, 0, TimeSpan.Zero),
            [
                new StatusUpdate(new DateTimeOffset(2026, 5, 24, 7, 0, 0, TimeSpan.Zero), "Label created"),
            ]),
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

